/**
 * User notification preferences model.
 *
 * Controls how and when notifications are delivered to users.
 * Currently supports email channel settings; designed for future
 * channel expansion.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': Send as events occur
 * - 'daily-digest': Batch into a daily summary
 * - 'weekly-digest': Batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Per-category subscription settings for email notifications.
 * Keys map to NotificationType values.
 */
export interface EmailCategoryPreferences {
  'order-confirmation': boolean;
  'order-status-update': boolean;
  'welcome': boolean;
  'user-updated': boolean;
}

/**
 * Email-specific notification preferences.
 */
export interface EmailNotificationPreferences {
  /** Whether email notifications are enabled at all */
  enabled: boolean;
  /** Delivery frequency */
  frequency: EmailFrequency;
  /** Per-category opt-in/out */
  categories: EmailCategoryPreferences;
}

/**
 * Full user notification preferences record.
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating preferences (userId required, rest optional with defaults).
 */
export interface CreatePreferencesInput {
  userId: string;
  email?: Partial<EmailNotificationPreferences & { categories?: Partial<EmailCategoryPreferences> }>;
}

/**
 * Input for updating preferences (all fields optional).
 */
export interface UpdatePreferencesInput {
  email?: Partial<EmailNotificationPreferences & { categories?: Partial<EmailCategoryPreferences> }>;
}

/**
 * Default email notification preferences — all enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: {
    'order-confirmation': true,
    'order-status-update': true,
    'welcome': true,
    'user-updated': true,
  },
};

/**
 * Check whether a notification type is enabled for a user's email preferences.
 */
export function isEmailNotificationEnabled(
  preferences: EmailNotificationPreferences,
  notificationType: NotificationType,
): boolean {
  if (!preferences.enabled) {
    return false;
  }
  return preferences.categories[notificationType] ?? false;
}

/**
 * Repository for UserNotificationPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user-preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    const categories = JSON.parse(record['emailCategories'] as string);
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as UserNotificationPreferences['email']['frequency'],
        categories,
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailCategories: JSON.stringify(entity.email.categories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 * - UserRepository (data layer) for user validation
 *
 * Creates default preferences (all enabled, immediate delivery) when a user
 * has no preferences record. Supports granular per-category and frequency settings.
 */

import type {
  UserNotificationPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
  EmailNotificationPreferences,
} from '../models/user-preferences.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get preferences for a user. Returns defaults if none exist.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    // Return default preferences without persisting
    const now = new Date();
    return {
      id: '',
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, categories: { ...DEFAULT_EMAIL_PREFERENCES.categories } },
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Create notification preferences for a user.
   */
  createPreferences(input: CreatePreferencesInput): UserNotificationPreferences {
    this.logger.info(`Creating preferences for user: ${input.userId}`);

    const user = this.userRepository.findById(input.userId);
    if (!user) {
      throw new Error(`User not found: ${input.userId}`);
    }

    const existing = this.preferencesRepository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const now = new Date();
    const emailInput = input.email ?? {};
    const categoriesInput = emailInput.categories ?? {};

    const preferences: UserNotificationPreferences = {
      id: generateId(),
      userId: input.userId,
      email: {
        enabled: emailInput.enabled ?? DEFAULT_EMAIL_PREFERENCES.enabled,
        frequency: emailInput.frequency ?? DEFAULT_EMAIL_PREFERENCES.frequency,
        categories: {
          'order-confirmation': categoriesInput['order-confirmation'] ?? DEFAULT_EMAIL_PREFERENCES.categories['order-confirmation'],
          'order-status-update': categoriesInput['order-status-update'] ?? DEFAULT_EMAIL_PREFERENCES.categories['order-status-update'],
          'welcome': categoriesInput['welcome'] ?? DEFAULT_EMAIL_PREFERENCES.categories['welcome'],
          'user-updated': categoriesInput['user-updated'] ?? DEFAULT_EMAIL_PREFERENCES.categories['user-updated'],
        },
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    return preferences;
  }

  /**
   * Update notification preferences for a user.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserNotificationPreferences {
    this.logger.info(`Updating preferences for user: ${userId}`);

    let existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      // Auto-create with defaults, then apply updates
      const user = this.userRepository.findById(userId);
      if (!user) {
        throw new Error(`User not found: ${userId}`);
      }
      existing = this.createPreferences({ userId });
    }

    const emailInput = input.email ?? {};
    const categoriesInput = emailInput.categories ?? {};

    const updatedEmail: EmailNotificationPreferences = {
      enabled: emailInput.enabled ?? existing.email.enabled,
      frequency: emailInput.frequency ?? existing.email.frequency,
      categories: {
        'order-confirmation': categoriesInput['order-confirmation'] ?? existing.email.categories['order-confirmation'],
        'order-status-update': categoriesInput['order-status-update'] ?? existing.email.categories['order-status-update'],
        'welcome': categoriesInput['welcome'] ?? existing.email.categories['welcome'],
        'user-updated': categoriesInput['user-updated'] ?? existing.email.categories['user-updated'],
      },
    };

    const updated = this.preferencesRepository.update(existing.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Delete preferences for a user (reverts to defaults).
   */
  deletePreferences(userId: string): boolean {
    this.logger.info(`Deleting preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      return false;
    }

    return this.preferencesRepository.delete(existing.id);
  }
}

