import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../../src/models/user-preferences.js';
import type { User } from '../../src/models/user.js';

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;
  let testUser: User;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo, userRepo);
    resetPreferencesIdCounter();

    testUser = {
      id: 'user-0001',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    userRepo.save(testUser);
  });

  describe('getPreferences', () => {
    it('should return default preferences when none exist', () => {
      const prefs = service.getPreferences('user-0001');

      expect(prefs.userId).toBe('user-0001');
      expect(prefs.id).toBe('');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories['order-confirmation']).toBe(true);
      expect(prefs.email.categories['order-status-update']).toBe(true);
      expect(prefs.email.categories['welcome']).toBe(true);
      expect(prefs.email.categories['user-updated']).toBe(true);
    });

    it('should return stored preferences when they exist', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { frequency: 'daily-digest' },
      });

      const prefs = service.getPreferences('user-0001');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.frequency).toBe('daily-digest');
    });
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-0001' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email).toEqual(DEFAULT_EMAIL_PREFERENCES);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: true,
          frequency: 'weekly-digest',
          categories: {
            'order-confirmation': true,
            'order-status-update': false,
          },
        },
      });

      expect(prefs.email.frequency).toBe('weekly-digest');
      expect(prefs.email.categories['order-status-update']).toBe(false);
      expect(prefs.email.categories['order-confirmation']).toBe(true);
      // Unspecified categories default to true
      expect(prefs.email.categories['welcome']).toBe(true);
    });

    it('should create preferences with email disabled', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      expect(prefs.email.enabled).toBe(false);
    });

    it('should throw if user does not exist', () => {
      expect(() => service.createPreferences({ userId: 'nonexistent' })).toThrow(
        'User not found: nonexistent',
      );
    });

    it('should throw if preferences already exist', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(() => service.createPreferences({ userId: 'user-0001' })).toThrow(
        'Preferences already exist for user: user-0001',
      );
    });

    it('should generate sequential IDs', () => {
      const user2: User = {
        id: 'user-0002',
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      userRepo.save(user2);

      const p1 = service.createPreferences({ userId: 'user-0001' });
      const p2 = service.createPreferences({ userId: 'user-0002' });

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('updatePreferences', () => {
    it('should update existing preferences', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'daily-digest' },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      // Other settings preserved
      expect(updated.email.enabled).toBe(true);
      expect(updated.email.categories['order-confirmation']).toBe(true);
    });

    it('should update category preferences', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: {
          categories: {
            'order-status-update': false,
            'welcome': false,
          },
        },
      });

      expect(updated.email.categories['order-status-update']).toBe(false);
      expect(updated.email.categories['welcome']).toBe(false);
      expect(updated.email.categories['order-confirmation']).toBe(true);
      expect(updated.email.categories['user-updated']).toBe(true);
    });

    it('should disable email entirely', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
    });

    it('should auto-create preferences if none exist', () => {
      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'weekly-digest' },
      });

      expect(updated.id).toBe('pref-0001');
      expect(updated.email.frequency).toBe('weekly-digest');
    });

    it('should throw if user does not exist and no preferences exist', () => {
      expect(() =>
        service.updatePreferences('nonexistent', { email: { enabled: false } }),
      ).toThrow('User not found: nonexistent');
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-0001' });

      const result = service.deletePreferences('user-0001');
      expect(result).toBe(true);

      // Should return defaults now
      const prefs = service.getPreferences('user-0001');
      expect(prefs.id).toBe('');
    });

    it('should return false if no preferences exist', () => {
      const result = service.deletePreferences('user-0001');
      expect(result).toBe(false);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
import type { UserNotificationPreferences } from '../../src/models/user-preferences.js';

describe('NotificationService with preferences', () => {
  let eventBus: EventBus;
  let db: Database;
  let prefsRepo: PreferencesRepository;
  let service: NotificationService;
  let emailAdapter: EmailAdapter;

  const alice = {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member' as const,
    createdAt: new Date(),
    updatedAt: new Date(),
  };

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    prefsRepo = new PreferencesRepository(db);
    service = new NotificationService(eventBus, prefsRepo);
    emailAdapter = new EmailAdapter();
    service.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
  });

  it('should send notification when user has no preferences (defaults)', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-0001',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: alice,
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(1);
    expect(service.getNotifications()).toHaveLength(1);
    expect(service.getNotifications()[0]?.status).toBe('sent');
  });

  it('should suppress notification when email is globally disabled', async () => {
    const now = new Date();
    const prefs: UserNotificationPreferences = {
      id: 'pref-0001',
      userId: 'user-0001',
      email: {
        enabled: false,
        frequency: 'immediate',
        categories: {
          'order-confirmation': true,
          'order-status-update': true,
          'welcome': true,
          'user-updated': true,
        },
      },
      createdAt: now,
      updatedAt: now,
    };
    prefsRepo.save(prefs);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-0001',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: alice,
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when specific category is disabled', async () => {
    const now = new Date();
    const prefs: UserNotificationPreferences = {
      id: 'pref-0001',
      userId: 'user-0001',
      email: {
        enabled: true,
        frequency: 'immediate',
        categories: {
          'order-confirmation': false,
          'order-status-update': true,
          'welcome': true,
          'user-updated': true,
        },
      },
      createdAt: now,
      updatedAt: now,
    };
    prefsRepo.save(prefs);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-0001',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: alice,
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should send notification when category is enabled', async () => {
    const now = new Date();
    const prefs: UserNotificationPreferences = {
      id: 'pref-0001',
      userId: 'user-0001',
      email: {
        enabled: true,
        frequency: 'immediate',
        categories: {
          'order-confirmation': true,
          'order-status-update': false,
          'welcome': false,
          'user-updated': false,
        },
      },
      createdAt: now,
      updatedAt: now,
    };
    prefsRepo.save(prefs);

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-0001',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: alice,
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(1);
  });

  it('should suppress welcome notification when welcome category is disabled', async () => {
    const now = new Date();
    const prefs: UserNotificationPreferences = {
      id: 'pref-0001',
      userId: 'user-0001',
      email: {
        enabled: true,
        frequency: 'immediate',
        categories: {
          'order-confirmation': true,
          'order-status-update': true,
          'welcome': false,
          'user-updated': true,
        },
      },
      createdAt: now,
      updatedAt: now,
    };
    prefsRepo.save(prefs);

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: alice,
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should work without preferences repository (backward compatible)', async () => {
    // Create service without preferences repo
    const serviceNoPref = new NotificationService(eventBus);
    serviceNoPref.registerAdapter(emailAdapter);

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: alice,
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // Both services received the event; the one without prefs should always send
    const emails = emailAdapter.getSentEmails();
    expect(emails.length).toBeGreaterThanOrEqual(1);
  });
});

